$ErrorActionPreference = "Stop"
$root = Get-Location

$target1 = Join-Path $root "SmartAttendance.Web\Pages\Settings\IraqTax.cshtml.cs"
$b64_1 = @"

"@
$bytes1 = [System.Convert]::FromBase64String($b64_1)
if (!(Test-Path (Split-Path $target1))) { New-Item -ItemType Directory -Path (Split-Path $target1) -Force | Out-Null }
[System.IO.File]::WriteAllBytes($target1, $bytes1)

$target2 = Join-Path $root "SmartAttendance.Web\Pages\Settings\IraqTax.cshtml"
$b64_2 = @"

"@
$bytes2 = [System.Convert]::FromBase64String($b64_2)
if (!(Test-Path (Split-Path $target2))) { New-Item -ItemType Directory -Path (Split-Path $target2) -Force | Out-Null }
[System.IO.File]::WriteAllBytes($target2, $bytes2)

$target3 = Join-Path $root "SmartAttendance.Web\wwwroot\css\iraq-tax-settings.css"
$b64_3 = @"

"@
$bytes3 = [System.Convert]::FromBase64String($b64_3)
if (!(Test-Path (Split-Path $target3))) { New-Item -ItemType Directory -Path (Split-Path $target3) -Force | Out-Null }
